        String fileName = args[0]; // User input from command line

        try {
            File file = new File(fileName);
            FileInputStream fis = new FileInputStream(file);

            int content;
            while ((content = fis.read()) != -1) {
                System.out.print((char) content);
            }

            fis.close();
